//! Container queries support for CSS Containment Level 3

use crate::values::specified::length::Length;
use std::fmt;
use style_traits::ToCss;

/// Represents a container size query, used to evaluate @container rules.
/// See: https://drafts.csswg.org/css-conditional-5/#container-queries
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct ContainerSizeQuery {
    /// The container width in pixels, if known
    width: Option<f32>,
    /// The container height in pixels, if known
    height: Option<f32>,
}

impl ContainerSizeQuery {
    /// Create a container size query with no container information.
    /// Used when no container size should be considered.
    pub const fn none() -> Self {
        ContainerSizeQuery {
            width: None,
            height: None,
        }
    }

    /// Create a container size query with explicit dimensions.
    pub const fn new(width: Option<f32>, height: Option<f32>) -> Self {
        ContainerSizeQuery { width, height }
    }

    /// Get the container width if available
    pub const fn width(&self) -> Option<f32> {
        self.width
    }

    /// Get the container height if available
    pub const fn height(&self) -> Option<f32> {
        self.height
    }

    /// Check if this query has no container information
    pub const fn is_none(&self) -> bool {
        matches!(self, ContainerSizeQuery { width: None, height: None })
    }
}

impl Default for ContainerSizeQuery {
    fn default() -> Self {
        Self::none()
    }
}

impl fmt::Display for ContainerSizeQuery {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(
            f,
            "ContainerSizeQuery {{ width: {:?}, height: {:?} }}",
            self.width, self.height
        )
    }
}

impl ToCss for ContainerSizeQuery {
    fn to_css<W>(&self, dest: &mut W) -> std::fmt::Result
    where
        W: std::fmt::Write,
    {
        match (self.width, self.height) {
            (Some(w), Some(h)) => write!(dest, "{}px x {}px", w, h),
            (Some(w), None) => write!(dest, "{}px x auto", w),
            (None, Some(h)) => write!(dest, "auto x {}px", h),
            (None, None) => write!(dest, "none"),
        }
    }
}

/// Represents a container condition in an @container rule.
/// Evaluates against container dimensions.
#[derive(Debug, Clone)]
pub enum ContainerCondition {
    /// A size query like (min-width: 400px)
    Size(SizeQuery),
    /// A logical AND of multiple conditions
    And(Vec<ContainerCondition>),
    /// A logical OR of multiple conditions
    Or(Vec<ContainerCondition>),
    /// A logical NOT of a condition
    Not(Box<ContainerCondition>),
}

impl ContainerCondition {
    /// Evaluate this container condition against the given container sizes
    pub fn matches(&self, query: ContainerSizeQuery) -> bool {
        match self {
            ContainerCondition::Size(sq) => sq.matches(query),
            ContainerCondition::And(conditions) => {
                conditions.iter().all(|cond| cond.matches(query))
            }
            ContainerCondition::Or(conditions) => {
                conditions.iter().any(|cond| cond.matches(query))
            }
            ContainerCondition::Not(cond) => !cond.matches(query),
        }
    }
}

/// Represents a size query feature like (min-width: 400px)
#[derive(Debug, Clone)]
pub enum SizeQuery {
    /// min-width query
    MinWidth(f32),
    /// max-width query
    MaxWidth(f32),
    /// width query (exact match)
    Width(f32),
    /// min-height query
    MinHeight(f32),
    /// max-height query
    MaxHeight(f32),
    /// height query (exact match)
    Height(f32),
    /// aspect-ratio query
    AspectRatio(f32, f32), // numerator, denominator
    /// min-aspect-ratio query
    MinAspectRatio(f32, f32),
    /// max-aspect-ratio query
    MaxAspectRatio(f32, f32),
    /// orientation query (portrait | landscape)
    Orientation(Orientation),
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Orientation {
    Portrait,
    Landscape,
}

impl SizeQuery {
    /// Evaluate this size query against container dimensions
    pub fn matches(&self, query: ContainerSizeQuery) -> bool {
        match self {
            SizeQuery::MinWidth(width) => {
                query.width().map_or(true, |w| w >= *width)
            }
            SizeQuery::MaxWidth(width) => {
                query.width().map_or(true, |w| w <= *width)
            }
            SizeQuery::Width(width) => {
                query.width().map_or(false, |w| (w - width).abs() < 0.01)
            }
            SizeQuery::MinHeight(height) => {
                query.height().map_or(true, |h| h >= *height)
            }
            SizeQuery::MaxHeight(height) => {
                query.height().map_or(true, |h| h <= *height)
            }
            SizeQuery::Height(height) => {
                query.height().map_or(false, |h| (h - height).abs() < 0.01)
            }
            SizeQuery::AspectRatio(num, denom) => {
                match (query.width(), query.height()) {
                    (Some(w), Some(h)) => {
                        let aspect = w / h;
                        let target_aspect = num / denom;
                        (aspect - target_aspect).abs() < 0.01
                    }
                    _ => true,
                }
            }
            SizeQuery::MinAspectRatio(num, denom) => {
                match (query.width(), query.height()) {
                    (Some(w), Some(h)) => {
                        let aspect = w / h;
                        let target_aspect = num / denom;
                        aspect >= target_aspect
                    }
                    _ => true,
                }
            }
            SizeQuery::MaxAspectRatio(num, denom) => {
                match (query.width(), query.height()) {
                    (Some(w), Some(h)) => {
                        let aspect = w / h;
                        let target_aspect = num / denom;
                        aspect <= target_aspect
                    }
                    _ => true,
                }
            }
            SizeQuery::Orientation(orientation) => {
                match (query.width(), query.height()) {
                    (Some(w), Some(h)) => {
                        let is_portrait = h >= w;
                        match orientation {
                            Orientation::Portrait => is_portrait,
                            Orientation::Landscape => !is_portrait,
                        }
                    }
                    _ => true,
                }
            }
        }
    }
}

